Here is a basic HEVC NAL parser in C++ that can parse SPS and PPS NAL units:
```cpp
#include <vector>
#include <bitset>

using namespace std;

enum class NALUnitType {
    TRAIL_N = 0,
    TRAIL_R = 1,
    TSA_N   = 2,
    TSA_R   = 3,
    STAP_A  = 4, 
    STAP_B  = 5, 
    MTAP16  = 6,
    MTAP24  = 7,
    FU_A    = 8,
    FU_B    = 9,
    SPS     = 32,
    PPS     = 33,
    VPS     = 34,
    SEI_PREFIX = 39,
    SEI_SUFFIX = 40
};

struct NALUnit {
    NALUnitType type;
    vector<uint8_t> data;
};

class HEVCParser {
public:
    vector<NALUnit> parse(vector<uint8_t>& data) {
        vector<NALUnit> nalUnits;
        uint32_t i = 0;
        while (i < data.size()) {
            // Find start code (0x00 00 00 01)
            uint32_t startCodePos = i;
            while (i < data.size() - 3 && data[i] == 0 && data[i+1] == 0 && data[i+2] == 0) {
                i += 3;
            }
            if (i >= data.size() - 3) break;
            if (data[i] != 1) { // Start code not found, move to next byte
                i++;
                continue;
            } 

            // Extract NAL unit type and size
            uint8_t nalUnitType = (data[startCodePos + 3] & 0x7E) >> 1;
            uint16_t nalUnitSize = 0;
            for (int j = 0; j < 2; j++) {
                nalUnitSize = (nalUnitSize << 8) | data[i + 1 + j];
            }
            i += 3; // Move past start code

            // Extract NAL unit data
            vector<uint8_t> nalUnitData(nalUnitSize);
            for (int j = 0; j < nalUnitSize

; j++) {
                nalUnitData[j] = data[i + j];
            }
            i += nalUnitSize;

            // Create NAL unit object
            NALUnit nalUnit;
            nalUnit.type = (NALUnitType)nalUnitType;
            nalUnit.data = nalUnitData;
            nalUnits.push_back(nalUnit);
        }
        return nalUnits;
    }

    void parseSPS(NALUnit& sps) {
        // SPS parsing logic here
    }

    void parsePPS(NALUnit& pps) {
        // PPS parsing logic here 
    }
};

int main() {
    vector<uint8_t> data = {0, 0, 0, 1, 0x27, 0x62, 0x01, 0x0c, 0x01, 0x94, 0x00, 0x00, 0x03, 0x00, 0x01, 0x00}; 
    // Contains one SPS NAL unit

    HEVCParser parser;
    vector<NALUnit> nalUnits = parser.parse(data);

    // Find and parse SPS
    for (NALUnit& nalUnit : nalUnits) {
        if (nalUnit.type == NALUnitType::SPS) {
            parser.parseSPS(nalUnit);
        }
    }
}
```

This parser scans through the input data to find start codes (0x00 00 00 01) which indicate the beginning of a NAL unit. It then extracts the NAL unit type, size, and data. The SPS and PPS NAL units are parsed by calling the `parseSPS()` and `parsePPS()` methods respectively. Let me know if you have any questions!

Here is an implementation of the parseSPS() method:
```cpp
void HEVCParser::parseSPS(NALUnit& sps) {
    // Extract raw byte sequence parameter set data
    vector<uint8_t>& data = sps.data;

    // Get SPS ID
    uint8_t spsId = (data[1] & 0x1F);

    // Get SPS size
    uint16_t spsSize = 0;
    for (int i = 0; i < 2; i++) {
        spsSize = (spsSize << 8) | data[2 + i]; 
    }

    // Parse profile_tier_level
    uint8_t ptlLength = data[4];
    uint8_t profile_space = (data[5] >> 6) & 0x3;
    uint8_t tier_flag   = (data[5] >> 5) & 0x1;
    uint8_t profile_idc = data[5] & 0x1F;

    // Parse pic_width_in_luma_samples and pic_height_in_luma_samples
    uint16_t picWidth  = 0;
    for (int i = 0; i < 2; i++) {
        picWidth = (picWidth << 8) | data[6 + i];
    }
    uint16_t picHeight = 0;
    for (int i = 0; i < 2; i++) {
        picHeight = (picHeight << 8) | data[8 + i]; 
    }

    // Parse bit depth and chroma format
    uint8_t bitDepth   = (data[10] & 0xF0) >> 4; 
    uint8_t chromaFormatIdc = data[10] & 0x0F;

    // There are more fields to parse...
}
```

This parses some of the key fields in the SPS NAL unit like:

- sps_id: Sequence parameter set ID 
- sps_size: Size of the SPS in bytes
- profile_tier_level: Profile, tier, and level information 
- pic_width_in_luma_samples: Picture width in luma samples
- pic_height_in_luma_samples: Picture height in luma samples
- bit_depth: Bit depth of luma and chroma
